/**
 * SETUP DATABASE: Inisialisasi Sheet dan Kolom
 */
function setupDatabase() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const sheets = getDbSchema();

  sheets.forEach(sh => {
    let sheet = ss.getSheetByName(sh.name);
    if (!sheet) {
      sheet = ss.insertSheet(sh.name);
      sheet.getRange(1, 1, 1, sh.header.length).setValues([sh.header]).setFontWeight('bold').setBackground('#d9ead3');
    } else {
      const lastCol = sheet.getLastColumn();
      if (lastCol > 0) {
        const headers = sheet.getRange(1, 1, 1, lastCol).getValues()[0];
        if (sh.name.includes('TRANSAKSI') && !headers.includes('Evidence')) {
          sheet.getRange(1, lastCol + 1).setValue('Evidence').setFontWeight('bold').setBackground('#d9ead3');
        }
      }
    }
  });

  // Default Data jika kosong - SECURED VIA DEFINTIVE SHA-256 HASH SEEDING
  const userSheet = ss.getSheetByName('MASTER_USER');
  if (userSheet.getLastRow() === 1) {
    const secureAdminHash = "5d69352e80556f082e66b450702c2e5b706c9bc9e5c46b5a3717dfb11961e626";
    userSheet.appendRow(['admin', secureAdminHash, 'Administrator', 'ADMIN', 'ALL']);
  }

  const jenisSheet = ss.getSheetByName('MASTER_JENIS_TRANSAKSI');
  if (jenisSheet.getLastRow() === 1) {
    jenisSheet.appendRow(['1', 'Payment Request', 'internal']);
    jenisSheet.appendRow(['2', 'Expense Claim', 'internal']);
    jenisSheet.appendRow(['3', 'Invoice BUJP', 'invoice']);
    jenisSheet.appendRow(['4', 'Invoice Stakeholder', 'stakeholder']);
  }

  return "Database Siap & Terupdate!";
}

