// FUNGSI UTAMA: doGet (Mendukung Web App & Jalur REST API Engine)
// -------------------------------------------------------------------------
function doGet(e) {
  if (e && e.parameter && e.parameter.action === "getAppData") {
    // SECURITY FALLBACK SYNC: Cegah alokasi data terpotong menjadi 0 akibat delay handshake klien
    const clientUsername = e.parameter.username || "";
    let secureRole = e.parameter.role;
    let secureWkAccess = e.parameter.wkAccess;

    if (clientUsername) {
      const serverCheck = verifyServerSideRole(clientUsername);
      if (serverCheck.active) {
        secureRole = serverCheck.user.role;
        secureWkAccess = serverCheck.user.wkAccess;
      }
    }

    var responseData = getAppData(secureRole, secureWkAccess);
    return ContentService.createTextOutput(JSON.stringify(responseData))
        .setMimeType(ContentService.MimeType.JSON);
  }

  return HtmlService.createTemplateFromFile('Index')
    .evaluate()
    .setTitle('Budget Monitoring V3.1')
    .setXFrameOptionsMode(HtmlService.XFrameOptionsMode.ALLOWALL)
    .addMetaTag('viewport', 'width=device-width, initial-scale=1');
}

// -------------------------------------------------------------------------
// API PIPELINE: Gerbang Tunggal Pemrosesan Mutasi Data POST (Vercel Polyfill Ready)
// -------------------------------------------------------------------------
function doPost(e) {
  try {
    var params = JSON.parse(e.postData.contents);
    var action = params.action;
    var data = params.data;
    var result;

    if (action === "loginUser") {
      result = loginUser(data.form);
    } else {
      // VALIDATION LAYER SERVER-SIDE: Ambil otoritas hak akses riil langsung dari DB Master
      const serverUserCheck = verifyServerSideRole(data.userData ? data.userData.username : '');
      if (!serverUserCheck.active) {
        return ContentService.createTextOutput(JSON.stringify({ success: false, message: "Akses Ditolak: Sesi Otorisasi Tidak Valid!" }))
            .setMimeType(ContentService.MimeType.JSON);
      }
      
      const secureUserData = serverUserCheck.user;

      if (action === "saveMasterPagu") {
        result = saveMasterPagu(data.payload, secureUserData);
      } else if (action === "deleteMasterPagu") {
        result = deleteMasterPagu(data.id, secureUserData);
      } else if (action === "saveTransaction") {
        result = saveTransaction(data.type, data.payload, secureUserData);
      } else if (action === "updateTransaction") {
        result = updateTransaction(data.id, data.sType, data.payload, secureUserData);
      } else if (action === "deleteData") {
        result = deleteData(data.id, data.sType, secureUserData);
      } else if (action === "updateUserProfile") {
        result = updateUserProfile(data.form);
      }
    }

    return ContentService.createTextOutput(JSON.stringify({ success: true, result: result }))
        .setMimeType(ContentService.MimeType.JSON);
  } catch (err) {
    return ContentService.createTextOutput(JSON.stringify({ success: false, message: err.toString() }))
        .setMimeType(ContentService.MimeType.JSON);
  }
}

/**
 * AUTH SYSTEM
 */
function loginUser(form) {
  try {
    const ss = SpreadsheetApp.getActiveSpreadsheet();
    const sheet = ss.getSheetByName('MASTER_USER');
    const data = sheet.getDataRange().getValues();
    const uInput = String(form.username).trim().toLowerCase();
    const pInput = String(form.password).trim();
    
    const hashedInput = computeSHA256(pInput);

    for (let i = 1; i < data.length; i++) {
      const dbUsername = String(data[i][0]).toLowerCase();
      const dbPassword = String(data[i][1]);

      const isPasswordValid = (dbPassword.length === 64) ? (dbPassword === hashedInput) : (dbPassword === pInput);

      if (dbUsername === uInput && isPasswordValid) {
        if (dbPassword.length !== 64) {
          sheet.getRange(i + 1, 2).setValue(hashedInput);
          ss.getSheetByName('LOG_ACTIVITY').appendRow([new Date(), uInput, "Migration", "Password auto-hashed to SHA-256 for security compliance"]);
        }
        
        ss.getSheetByName('LOG_ACTIVITY').appendRow([new Date(), uInput, "Login Success", "User logged into Budget Monitoring Engine"]);
        return { success: true, user: { username: data[i][0], nama: data[i][2], role: data[i][3], wkAccess: data[i][4] }};
      }
    }
    
    ss.getSheetByName('LOG_ACTIVITY').appendRow([new Date(), uInput, "Login Failed", "Unauthorized access attempt with invalid password"]);
    return { success: false, message: 'Username atau Password salah!' };
  } catch (e) { return { success: false, message: e.toString() }; }
}

/**
 * HELPER COMPUTE SHA-256 CRYPTO ENGINE
 */
function computeSHA256(input) {
  const rawHash = Utilities.computeDigest(Utilities.DigestAlgorithm.SHA_256, input, Utilities.Charset.UTF_8);
  let output = "";
  for (let i = 0; i < rawHash.length; i++) {
    let byteValue = rawHash[i];
    if (byteValue < 0) byteValue += 256;
    let byteString = byteValue.toString(16);
    if (byteString.length == 1) byteString = "0" + byteString;
    output += byteString;
  }
  return output;
}

